mapper.insert:
INSERT INTO ea_user_datasource_permission (
    user_id, datasource_id, permission_type, creator_id, updater_id, deleted
) VALUES (
    #{userId}, #{datasourceId}, #{permissionType}, #{creatorId}, #{updaterId}, 0
)

mapper.update:
UPDATE ea_user_datasource_permission
SET deleted = id, updater_id = #{updaterId}, updated_time = CURRENT_TIMESTAMP
WHERE user_id = #{userId}
  AND datasource_id = #{datasourceId}
  AND deleted = 0

mapper.select:
